package com.chaobo.scm.supplier.interfaces.web;
import com.chaobo.scm.common.api.*;import com.chaobo.scm.supplier.application.asn.event.*;import jakarta.servlet.http.*;import jakarta.validation.*;import jakarta.validation.constraints.*;import org.springframework.web.bind.annotation.*;import java.math.*;import java.time.*;
@RestController @RequestMapping("/internal/supplier/v1/wms/asns")public class WmsAsnOpenApiController{private final WmsAsnEventConsumerApplicationService service;public WmsAsnOpenApiController(WmsAsnEventConsumerApplicationService service){this.service=service;}@PostMapping("/events")public ApiResponse<Void> consume(@Valid @RequestBody Request body,HttpServletRequest request){if(!"WMS".equals(request.getHeader("X-Source-System")))throw new com.chaobo.scm.common.error.BusinessException(com.chaobo.scm.common.error.ErrorCode.FORBIDDEN,"来源系统必须是WMS");service.consume(new WmsAsnEvent(request.getHeader("X-Event-Code"),body.eventType(),body.asnId(),body.appointmentNo(),body.arrivedAt(),body.receivedQuantity(),body.rejectedQuantity(),body.lines()==null?java.util.List.of():body.lines().stream().map(v->new WmsAsnEvent.Line(v.asnLineId(),v.receivedQuantity(),v.rejectedQuantity(),v.qualityStatus(),v.qualityReason())).toList()));return ApiResponse.success(null,request.getHeader("X-Request-Id"),request.getHeader("X-Trace-Id"));}public record Request(@NotBlank String eventType,@Positive long asnId,String appointmentNo,OffsetDateTime arrivedAt,BigDecimal receivedQuantity,BigDecimal rejectedQuantity,java.util.List<@Valid Line> lines){}public record Line(@Positive long asnLineId,@NotNull @DecimalMin("0")BigDecimal receivedQuantity,@NotNull @DecimalMin("0")BigDecimal rejectedQuantity,@Min(1)@Max(3)int qualityStatus,String qualityReason){} }
